import{G as e,c as t,b as r,ae as l}from"./chunks/framework.Cpb2nuHT.js";const p=JSON.parse('{"title":"MySQL 执行 SQL 时权限检查在哪个阶段？","description":"","frontmatter":{"title":"MySQL 执行 SQL 时权限检查在哪个阶段？","date":"2024-08-07T14:35:20.000Z","tags":["MySQL"],"author":"花木凋零成兰"},"headers":[],"relativePath":"Database/MySQL/MySQL执行SQL时权限检查在哪个阶段？.md","filePath":"Database/MySQL/MySQL执行SQL时权限检查在哪个阶段？.md","lastUpdated":1723362724000}'),o={name:"Database/MySQL/MySQL执行SQL时权限检查在哪个阶段？.md"};function s(_,a,n,i,S,d){return r(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1723041320000"},[...a[0]||(a[0]=[l('<h1 id="mysql-执行-sql-时权限检查在哪个阶段" tabindex="-1">MySQL 执行 SQL 时权限检查在哪个阶段？ <a class="header-anchor" href="#mysql-执行-sql-时权限检查在哪个阶段" aria-label="Permalink to &quot;MySQL 执行 SQL 时权限检查在哪个阶段？&quot;">​</a></h1><blockquote><p><a href="https://xiaolincoding.com/mysql/base/how_select.html" target="_blank" rel="noreferrer">学习MySQL执行SQL语句流程</a></p></blockquote><p>在优化器之前和执行器中都会进行权限检查;</p><ul><li>在解析器解析完后优化器之前, 会调用 <code>precheck</code> 验证权限; 此时只是做简单的验证;</li><li>在执行器中进行权限验证, 此时验证通过则说明用户有执行SQL语句的权限;</li></ul><p>在上述两个阶段的权限检查中, 最主要的应该还是执行器中的权限验证; 因为在 SQL 语句的执行过程中, 可以会使用到触发器, <strong>触发器需要在执行器阶段才能确定</strong>, 即优化器之前虽然验证权限通过, 但是在触发器执行的过程中可能会涉及到其他的表, 用户不一定有操作其他表的权限;</p><p>所以, 在执行器阶段进行权限检查通过才算是用户具有完全的权限;</p><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://segmentfault.com/q/1010000020193349" target="_blank" rel="noreferrer">MySQL的sql语句的权限检查在执行器还是分析器阶段？</a></li></ul>',8)])])}const L=e(o,[["render",s]]);export{p as __pageData,L as default};
